 45→	for i := start; i < end; i++ {
 46→		s := filtered[i]
 47→		prefix := "  "
 48→		if i == cursor {
 49→			prefix = listCursorStyle.Render("> ")
 50→		}
 51→
 52→		line := renderCheckpointRow(s)
 53→
 54→		if i == cursor {
 55→			sb.WriteString(prefix + lipgloss.NewStyle().Bold(true).Render(line))
 56→		} else {
 57→			sb.WriteString(prefix + line)
 58→		}
 59→		sb.WriteString("\n")
 60→	}
 61→
 62→	return sb.String()
 63→}
