 65→func renderCheckpointRow(s checkpoint.CheckpointSummary) string {
 66→	agent := agentBadgeStyle.Render(truncate(s.Agent, 12))
 67→	timeAgo := dimStyle.Render(formatTimeAgo(s.CreatedAt))
 68→	branch := branchStyle.Render(truncate(s.Branch, 20))
 69→	hash := hashStyle.Render(truncateHash(s.CommitHash))
 70→
 71→	ctx := ""
 72→	if s.Context != "" {
 73→		ctx = contextStyle.Render(truncate(s.Context, 40))
 74→	}
 75→
