package dashboard

import (
	"fmt"
	"strings"
	"time"

	"github.com/charmbracelet/lipgloss"

	"github.com/jcleira/entire-local/pkg/checkpoint"
)

func renderCheckpointList(summaries []checkpoint.CheckpointSummary, cursor int, height int, filter string) string {
	filtered := filterSummaries(summaries, filter)

	var sb strings.Builder

	header := headerStyle.Render("Checkpoints")
	if filter != "" {
		header += " " + filterStyle.Render("[/"+filter+"]")
	}
	header += dimStyle.Render(fmt.Sprintf(" (%d)", len(filtered)))
	sb.WriteString(header)
	sb.WriteString("\n")

	if len(filtered) == 0 {
		sb.WriteString(dimStyle.Render("  No checkpoints found"))
		return sb.String()
	}

	visibleHeight := height - 4
	if visibleHeight < 1 {
		visibleHeight = 10
	}

	start := 0
	if cursor >= visibleHeight {
		start = cursor - visibleHeight + 1
	}
	end := start + visibleHeight
	if end > len(filtered) {
		end = len(filtered)
	}

	for i := start; i < end; i++ {
		s := filtered[i]
		prefix := "  "
		if i == cursor {
			prefix = listCursorStyle.Render("> ")
		}

		line := renderCheckpointRow(s)

		if i == cursor {
			sb.WriteString(prefix + lipgloss.NewStyle().Bold(true).Render(line))
		} else {
			sb.WriteString(prefix + line)
		}
		sb.WriteString("\n")
	}

	return sb.String()
}

func renderCheckpointRow(s checkpoint.CheckpointSummary) string {
	agent := agentBadgeStyle.Render(truncate(s.Agent, 12))
	timeAgo := dimStyle.Render(formatTimeAgo(s.CreatedAt))
	branch := branchStyle.Render(truncate(s.Branch, 20))
	hash := hashStyle.Render(truncateHash(s.CommitHash))

	ctx := ""
	if s.Context != "" {
		ctx = contextStyle.Render(truncate(s.Context, 40))
	}

	stats := ""
	if s.Additions > 0 || s.Deletions > 0 {
		stats = addStyle.Render(fmt.Sprintf("+%d", s.Additions)) + " " +
			delStyle.Render(fmt.Sprintf("-%d", s.Deletions))
	}

	parts := []string{agent, timeAgo, branch, hash}
	if ctx != "" {
		parts = append(parts, ctx)
	}
	if stats != "" {
		parts = append(parts, stats)
	}

	return strings.Join(parts, "  ")
}

func filterSummaries(summaries []checkpoint.CheckpointSummary, filter string) []checkpoint.CheckpointSummary {
	if filter == "" {
		return summaries
	}

	f := strings.ToLower(filter)
	var result []checkpoint.CheckpointSummary
	for _, s := range summaries {
		if strings.Contains(strings.ToLower(s.Branch), f) ||
			strings.Contains(strings.ToLower(s.Agent), f) ||
			strings.Contains(strings.ToLower(s.Context), f) ||
			strings.Contains(strings.ToLower(s.CommitHash), f) {
			result = append(result, s)
		}
	}
	return result
}

func formatTimeAgo(t time.Time) string {
	if t.IsZero() {
		return "unknown"
	}
	d := time.Since(t)
	switch {
	case d < time.Minute:
		return "just now"
	case d < time.Hour:
		m := int(d.Minutes())
		return fmt.Sprintf("%dm ago", m)
	case d < 24*time.Hour:
		h := int(d.Hours())
		return fmt.Sprintf("%dh ago", h)
	default:
		days := int(d.Hours() / 24)
		return fmt.Sprintf("%dd ago", days)
	}
}

func truncate(s string, max int) string {
	if len(s) <= max {
		return s
	}
	return s[:max-1] + "…"
}

func truncateHash(hash string) string {
	if len(hash) > 7 {
		return hash[:7]
	}
	return hash
}

