package dashboard

import (
	"fmt"
	"strings"

	"github.com/charmbracelet/lipgloss"

	"github.com/jcleira/entire-local/pkg/checkpoint"
)

func renderCheckpointDetail(cp *checkpoint.Checkpoint, transcript []checkpoint.TranscriptEntry, width, height int) string {
	if cp == nil {
		return dimStyle.Render("Loading checkpoint...")
	}

	header := renderDetailHeader(cp)

	contentHeight := height - 8
	if contentHeight < 5 {
		contentHeight = 5
	}

	leftWidth := width/3 - 2
	if leftWidth < 20 {
		leftWidth = 20
	}
	rightWidth := width - leftWidth - 6
	if rightWidth < 30 {
		rightWidth = 30
	}

	leftPane := renderFileList(cp.Diff, leftWidth, contentHeight)
	rightPane := renderTranscriptPane(transcript, rightWidth, contentHeight)

	content := lipgloss.JoinHorizontal(lipgloss.Top,
		panelStyle.Width(leftWidth).Render(leftPane),
		panelStyle.Width(rightWidth).Render(rightPane),
	)

	return lipgloss.JoinVertical(lipgloss.Left, header, "", content)
}

func renderDetailHeader(cp *checkpoint.Checkpoint) string {
	var parts []string

	parts = append(parts, headerStyle.Render("Checkpoint Detail"))
	parts = append(parts, "")

	row1 := fmt.Sprintf(
		"%s  %s  %s",
		hashStyle.Render("commit "+truncateHash(cp.CommitHash)),
		branchStyle.Render(cp.Branch),
		agentBadgeStyle.Render(fmt.Sprintf("%s %d%%", cp.Agent, cp.AgentPercent)),
	)
	parts = append(parts, "  "+row1)

	if cp.Session.TotalTokens > 0 || cp.Session.Duration != "" {
		row2 := fmt.Sprintf(
			"%s  %s",
			dimStyle.Render(fmt.Sprintf("tokens: %d", cp.Session.TotalTokens)),
			dimStyle.Render(fmt.Sprintf("duration: %s", cp.Session.Duration)),
		)
		parts = append(parts, "  "+row2)
	}

	if cp.Context != "" {
		ctx := cp.Context
		if len(ctx) > 80 {
			ctx = ctx[:80] + "..."
		}
		parts = append(parts, "  "+contextStyle.Render(ctx))
	}

	return strings.Join(parts, "\n")
}

func renderFileList(diff string, width, height int) string {
	if diff == "" {
		return dimStyle.Render("No diff available")
	}

	var files []string
	for _, line := range strings.Split(diff, "\n") {
		if strings.HasPrefix(line, "diff --git") {
			parts := strings.Fields(line)
			if len(parts) >= 4 {
				fname := strings.TrimPrefix(parts[3], "b/")
				files = append(files, fname)
			}
		}
	}

	if len(files) == 0 {
		return dimStyle.Render("No files changed")
	}

	var sb strings.Builder
	sb.WriteString(titleStyle.Render(fmt.Sprintf("Files (%d)", len(files))))
	sb.WriteString("\n")

	max := height - 2
	if max > len(files) {
		max = len(files)
	}

	for i := range max {
		f := files[i]
		if len(f) > width-4 {
			f = "…" + f[len(f)-width+5:]
		}
		sb.WriteString("  " + f + "\n")
	}

	if len(files) > max {
		sb.WriteString(dimStyle.Render(fmt.Sprintf("  +%d more", len(files)-max)))
	}

	return sb.String()
}

