package dashboard

import (
	"strings"

	"github.com/jcleira/entire-local/pkg/checkpoint"
)

func renderTranscriptPane(entries []checkpoint.TranscriptEntry, width, height int) string {
	if len(entries) == 0 {
		return dimStyle.Render("Loading transcript...")
	}

	var sb strings.Builder
	sb.WriteString(titleStyle.Render("Transcript"))
	sb.WriteString("\n")

	lines := 0
	maxLines := height - 2

	for _, e := range entries {
		if lines >= maxLines {
			break
		}

		switch {
		case e.Role == "human" || e.Role == "user":
			content := e.Content
			if len(content) > width-6 {
				content = content[:width-6] + "..."
			}
			sb.WriteString(userMsgStyle.Render("  > ") + content + "\n")
			lines++

		case e.Role == "assistant":
			if e.ToolName != "" {
				sb.WriteString(toolBadgeStyle.Render("  ["+e.ToolName+"]") + "\n")
				lines++
				continue
			}
			content := e.Content
			if content == "" {
				continue
			}
			contentLines := strings.Split(content, "\n")
			for _, cl := range contentLines {
				if lines >= maxLines {
					break
				}
				if len(cl) > width-6 {
					cl = cl[:width-6] + "..."
				}
				sb.WriteString(assistantMsgStyle.Render("  ") + cl + "\n")
				lines++
			}

		case e.Type == "tool_result":
			sb.WriteString(dimStyle.Render("  [result]") + "\n")
			lines++

		default:
			if e.Content != "" {
				content := e.Content
				if len(content) > width-6 {
					content = content[:width-6] + "..."
				}
				sb.WriteString("  " + content + "\n")
				lines++
			}
		}
	}

	return sb.String()
}

package dashboard

import (
	"strings"

	"github.com/charmbracelet/lipgloss"
)

func renderHelp(width, height int) string {
	bindings := []struct{ key, desc string }{
		{"j/k", "Navigate up/down"},
		{"Enter/l", "Select checkpoint"},
		{"Esc/h", "Go back"},
		{"/", "Filter checkpoints"},
		{"r", "Refresh data"},
		{"?", "Toggle help"},
		{"q", "Quit"},
	}

	var sb strings.Builder
	sb.WriteString(headerStyle.Render("Keyboard Shortcuts"))
	sb.WriteString("\n\n")

	for _, b := range bindings {
		sb.WriteString("  ")
		sb.WriteString(helpKeyStyle.Render(padRight(b.key, 12)))
		sb.WriteString(helpDescStyle.Render(b.desc))
		sb.WriteString("\n")
	}

	sb.WriteString("\n")
	sb.WriteString(dimStyle.Render("  Press ? or Esc to close"))

	content := sb.String()

	boxWidth := 40
	box := lipgloss.NewStyle().
		Border(lipgloss.RoundedBorder()).
		BorderForeground(primary).
		Padding(1, 2).
		Width(boxWidth).
		Render(content)

	return lipgloss.Place(width, height,
		lipgloss.Center, lipgloss.Center,
		box,
	)
}

func padRight(s string, n int) string {
	if len(s) >= n {
		return s
	}
	return s + strings.Repeat(" ", n-len(s))
}

