func renderCheckpointBlock(s checkpoint.CheckpointSummary, width int) string {
	branch := branchStyle.Render(truncate(s.Branch, 30))
	hash := hashStyle.Render(truncateHash(s.CommitHash))
	timeAgo := dimStyle.Render(formatTimeAgo(s.CreatedAt))
	rightPart := hash + "   " + timeAgo
	padding := width - lipgloss.Width(branch) - lipgloss.Width(rightPart)
	if padding < 2 {
		padding = 2
	}
	line1 := branch + strings.Repeat(" ", padding) + rightPart

	var metaParts []string
	metaParts = append(metaParts, agentBadgeStyle.Render(truncate(s.Agent, 12)))
	if s.AgentPercent > 0 {
		metaParts = append(metaParts, dimStyle.Render(fmt.Sprintf("%d%%", s.AgentPercent)))
	}
	if s.TotalTokens > 0 {
		metaParts = append(metaParts, dimStyle.Render(fmt.Sprintf("%s tokens", formatNumber(s.TotalTokens))))
	}
	if s.Duration != "" {
		metaParts = append(metaParts, dimStyle.Render(s.Duration))
	}
	if s.Additions > 0 || s.Deletions > 0 {
