		return line1 + "\n" + line2 + "\n" + line3
	}
	return line1 + "\n" + line2
}

func filterSummaries(summaries []checkpoint.CheckpointSummary, filter string) []checkpoint.CheckpointSummary {
	if filter == "" {
		return summaries
	}

	f := strings.ToLower(filter)
	var result []checkpoint.CheckpointSummary
	for _, s := range summaries {
		if strings.Contains(strings.ToLower(s.Branch), f) ||
			strings.Contains(strings.ToLower(s.Agent), f) ||
			strings.Contains(strings.ToLower(s.Context), f) ||
			strings.Contains(strings.ToLower(s.CommitHash), f) {
			result = append(result, s)
		}
	}
	return result
}

func formatTimeAgo(t time.Time) string {
	if t.IsZero() {
		return "unknown"
	}
	d := time.Since(t)
	switch {
	case d < time.Minute:
		return "just now"
	case d < time.Hour:
		m := int(d.Minutes())
		return fmt.Sprintf("%dm ago", m)
	case d < 24*time.Hour:
		h := int(d.Hours())
		return fmt.Sprintf("%dh ago", h)
	default:
		days := int(d.Hours() / 24)
		return fmt.Sprintf("%dd ago", days)
	}
}

func formatNumber(n int) string {
	if n >= 1000 {
		return fmt.Sprintf("%d,%03d", n/1000, n%1000)
	}
	return fmt.Sprintf("%d", n)
}

func truncate(s string, max int) string {
	if len(s) <= max {
		return s
	}
	return s[:max-1] + "…"
}

func truncateHash(hash string) string {
	if len(hash) > 7 {
		return hash[:7]
	}
	return hash
}

