package dashboard

import (
	"strings"

	"github.com/jcleira/entire-local/pkg/checkpoint"
)

func renderTranscriptPane(entries []checkpoint.TranscriptEntry, width, height int) string {
	if len(entries) == 0 {
		return dimStyle.Render("Loading transcript...")
	}

	var sb strings.Builder
	sb.WriteString(titleStyle.Render("Transcript"))
	sb.WriteString("\n")

	lines := 0
	maxLines := height - 2

	for _, e := range entries {
		if lines >= maxLines {
			break
		}

		switch {
		case e.Role == "human" || e.Role == "user":
			content := e.Content
			if len(content) > width-6 {
				content = content[:width-6] + "..."
			}
			sb.WriteString(userMsgStyle.Render("  > ") + content + "\n")
			lines++

		case e.Role == "assistant":
			if e.ToolName != "" {
				sb.WriteString(toolBadgeStyle.Render("  ["+e.ToolName+"]") + "\n")
				lines++
				continue
			}
			content := e.Content
			if content == "" {
				continue
			}
			contentLines := strings.Split(content, "\n")
			for _, cl := range contentLines {
				if lines >= maxLines {
					break
				}
				if len(cl) > width-6 {
					cl = cl[:width-6] + "..."
				}
				sb.WriteString(assistantMsgStyle.Render("  ") + cl + "\n")
				lines++
			}

		case e.Type == "tool_result":
			sb.WriteString(dimStyle.Render("  [result]") + "\n")
			lines++

		default:
			if e.Content != "" {
				content := e.Content
				if len(content) > width-6 {
					content = content[:width-6] + "..."
				}
				sb.WriteString("  " + content + "\n")
				lines++
			}
		}
	}

	return sb.String()
}

