	}

	contentWidth := width - 4
	if contentWidth < 40 {
		contentWidth = 40
	}

	for i := start; i < end; i++ {
		s := filtered[i]
		block := renderCheckpointBlock(s, contentWidth)

		if i == cursor {
			sb.WriteString(selectedRowStyle.Render(block))
		} else {
			sb.WriteString(normalRowStyle.Render(block))
		}
		sb.WriteString("\n")
	}

	if len(filtered) > visibleHeight {
		sb.WriteString(scrollIndicatorStyle.Render(fmt.Sprintf("  (%d/%d)", cursor+1, len(filtered))))
	}

	return sb.String()
}

func renderCheckpointBlock(s checkpoint.CheckpointSummary, width int) string {
	branch := branchStyle.Render(truncate(s.Branch, 30))
	hash := hashStyle.Render(truncateHash(s.CommitHash))
	timeAgo := dimStyle.Render(formatTimeAgo(s.CreatedAt))
	rightPart := hash + "   " + timeAgo
	padding := width - lipgloss.Width(branch) - lipgloss.Width(rightPart)
	if padding < 2 {
		padding = 2
	}
	line1 := branch + strings.Repeat(" ", padding) + rightPart

	var metaParts []string
	metaParts = append(metaParts, agentBadgeStyle.Render(truncate(s.Agent, 12)))
	if s.AgentPercent > 0 {
		metaParts = append(metaParts, dimStyle.Render(fmt.Sprintf("%d%%", s.AgentPercent)))
	}
	if s.TotalTokens > 0 {
		metaParts = append(metaParts, dimStyle.Render(fmt.Sprintf("%s tokens", formatNumber(s.TotalTokens))))
	}
	if s.Duration != "" {
		metaParts = append(metaParts, dimStyle.Render(s.Duration))
	}
	if s.Additions > 0 || s.Deletions > 0 {
		metaParts = append(metaParts,
			addStyle.Render(fmt.Sprintf("+%d", s.Additions))+"/"+
				delStyle.Render(fmt.Sprintf("-%d", s.Deletions)))
	}
	if s.FileCount > 0 {
		metaParts = append(metaParts, dimStyle.Render(fmt.Sprintf("%d files", s.FileCount)))
	}
	line2 := strings.Join(metaParts, "   ")

	line3 := ""
	if s.Context != "" {
		ctx := s.Context
		if len(ctx) > width {
			ctx = ctx[:width-1] + "…"
		}
		line3 = dimStyle.Render(ctx)
	}

	if line3 != "" {
		return line1 + "\n" + line2 + "\n" + line3
	}
	return line1 + "\n" + line2
}

func filterSummaries(summaries []checkpoint.CheckpointSummary, filter string) []checkpoint.CheckpointSummary {
	if filter == "" {
		return summaries
	}

	f := strings.ToLower(filter)
	var result []checkpoint.CheckpointSummary
	for i := range summaries {
		if strings.Contains(strings.ToLower(summaries[i].Branch), f) ||
			strings.Contains(strings.ToLower(summaries[i].Agent), f) ||
			strings.Contains(strings.ToLower(summaries[i].Context), f) ||
			strings.Contains(strings.ToLower(summaries[i].CommitHash), f) {
			result = append(result, summaries[i])
		}
	}
	return result
}

func formatTimeAgo(t time.Time) string {
	if t.IsZero() {
		return "unknown"
	}
	d := time.Since(t)
	switch {
	case d < time.Minute:
		return "just now"
	case d < time.Hour:
		m := int(d.Minutes())
		return fmt.Sprintf("%dm ago", m)
	case d < 24*time.Hour:
		h := int(d.Hours())
		return fmt.Sprintf("%dh ago", h)
	default:
		days := int(d.Hours() / 24)
		return fmt.Sprintf("%dd ago", days)
	}
}

func formatNumber(n int) string {
	if n >= 1000 {
		return fmt.Sprintf("%d,%03d", n/1000, n%1000)
	}
	return fmt.Sprintf("%d", n)
}

func truncate(s string, max int) string {
	if len(s) <= max {
		return s
	}
	return s[:max-1] + "…"
}

func truncateHash(hash string) string {
	if len(hash) > 7 {
		return hash[:7]
	}
	return hash
}

package dashboard

import (
	"fmt"
	"strings"

	"github.com/charmbracelet/bubbles/key"
	tea "github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/lipgloss"

	"github.com/jcleira/entire-local/pkg/checkpoint"
)

type model struct {
	loader     *checkpoint.Loader
	summaries  []checkpoint.CheckpointSummary
	stats      checkpoint.OverviewStats
	detail     *checkpoint.Checkpoint
	transcript []checkpoint.TranscriptEntry

	screen       screen
	cursor       int
	width        int
	height       int
	filter       string
	filtering    bool
	showHelp     bool
	err          error
	detailTab    detailTab
	scrollOffset int
	maxScroll    int
}

func RunDashboard(loader *checkpoint.Loader) error {
	m := model{
		loader: loader,
		screen: screenOverview,
		width:  80,
		height: 24,
	}

	p := tea.NewProgram(m, tea.WithAltScreen())
	_, err := p.Run()
	return err
}

func (m model) Init() tea.Cmd {
	return m.loadCheckpoints()
}

func (m model) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {
	case tea.WindowSizeMsg:
		m.width = msg.Width
		m.height = msg.Height
		return m, nil

	case tea.KeyMsg:
		if m.filtering {
			return m.handleFilterInput(msg)
		}
		return m.handleKeyPress(msg)

	case checkpointsLoadedMsg:
		m.summaries = msg.summaries
		m.stats = checkpoint.ComputeStats(msg.summaries)
		return m, nil

	case checkpointDetailLoadedMsg:
		m.detail = msg.checkpoint
		return m, nil

	case transcriptLoadedMsg:
		m.transcript = msg.entries
		return m, nil

	case errMsg:
		m.err = msg.err
		return m, nil
	}

	return m, nil
}

func (m model) View() string {
	if m.showHelp {
		return renderHelp(m.width, m.height)
	}

	if m.err != nil {
		return lipgloss.Place(m.width, m.height,
			lipgloss.Center, lipgloss.Center,
			lipgloss.NewStyle().Foreground(errClr).Render("Error: "+m.err.Error()),
		)
	}

	var content string

	switch m.screen {
	case screenOverview:
		overview := renderOverview(m.stats, m.width)
		overviewLines := strings.Count(overview, "\n") + 1
		listHeight := m.height - overviewLines - 3
		if listHeight < 5 {
			listHeight = 5
		}
		list := renderCheckpointList(m.summaries, m.cursor, listHeight, m.filter, m.width)
		content = lipgloss.JoinVertical(lipgloss.Left, overview, "", list)

	case screenDetail:
		content = renderCheckpointDetail(m.detail, m.transcript, m.width, m.height-2, m.detailTab, m.scrollOffset)
	}

	footer := m.renderFooter()

	return lipgloss.JoinVertical(lipgloss.Left,
		content,
		footer,
	)
}

func (m model) handleKeyPress(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	switch {
	case key.Matches(msg, keys.Quit):
		return m, tea.Quit

	case key.Matches(msg, keys.Help):
		m.showHelp = !m.showHelp
		return m, nil

	case key.Matches(msg, keys.Refresh):
		return m, m.loadCheckpoints()

	case key.Matches(msg, keys.Filter):
		if m.screen == screenOverview {
			m.filtering = true
			return m, nil
		}
	}

	switch m.screen {
	case screenOverview:
		return m.handleOverviewKeys(msg)
	case screenDetail:
		return m.handleDetailKeys(msg)
	}

	return m, nil
}

func (m model) handleOverviewKeys(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	filtered := filterSummaries(m.summaries, m.filter)

	switch {
	case key.Matches(msg, keys.Down):
		if m.cursor < len(filtered)-1 {
			m.cursor++
		}

	case key.Matches(msg, keys.Up):
		if m.cursor > 0 {
			m.cursor--
		}

	case key.Matches(msg, keys.Enter):
		if len(filtered) > 0 && m.cursor < len(filtered) {
			selected := filtered[m.cursor]
			m.screen = screenDetail
			m.detail = nil
			m.transcript = nil
			m.detailTab = tabOverview
			m.scrollOffset = 0
			return m, tea.Batch(
				m.loadDetail(selected.ID),
				m.loadTranscript(selected.ID),
			)
		}
	}

	return m, nil
}

func (m model) handleDetailKeys(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	switch {
	case key.Matches(msg, keys.Back):
		m.screen = screenOverview
		m.detail = nil
		m.transcript = nil
		m.scrollOffset = 0
		return m, nil

	case key.Matches(msg, keys.Tab):
		m.detailTab = (m.detailTab + 1) % 4
		m.scrollOffset = 0
		return m, nil

	case key.Matches(msg, keys.ShiftTab):
		m.detailTab = (m.detailTab + 3) % 4
		m.scrollOffset = 0
		return m, nil

	case key.Matches(msg, keys.Num1):
		m.detailTab = tabOverview
		m.scrollOffset = 0
		return m, nil

	case key.Matches(msg, keys.Num2):
		m.detailTab = tabFiles
		m.scrollOffset = 0
		return m, nil

	case key.Matches(msg, keys.Num3):
		m.detailTab = tabTranscript
		m.scrollOffset = 0
		return m, nil

	case key.Matches(msg, keys.Num4):
		m.detailTab = tabPlan
		m.scrollOffset = 0
		return m, nil

	case key.Matches(msg, keys.Down):
		if m.scrollOffset < m.maxScroll {
			m.scrollOffset++
		}
		return m, nil

	case key.Matches(msg, keys.Up):
		if m.scrollOffset > 0 {
			m.scrollOffset--
		}
		return m, nil
	}

	return m, nil
}

func (m model) handleFilterInput(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	switch msg.Type {
	case tea.KeyEnter, tea.KeyEscape:
		m.filtering = false
		if msg.Type == tea.KeyEscape {
			m.filter = ""
		}
		m.cursor = 0
		return m, nil
	case tea.KeyBackspace:
		if len(m.filter) > 0 {
			m.filter = m.filter[:len(m.filter)-1]
		}
		m.cursor = 0
		return m, nil
	default:
		if len(msg.Runes) > 0 {
			m.filter += string(msg.Runes)
			m.cursor = 0
		}
		return m, nil
	}
}

func (m model) renderFooter() string {
	if m.filtering {
		return footerStyle.Render(fmt.Sprintf("Filter: %s█", m.filter))
	}

	var parts []string
	switch m.screen {
	case screenOverview:
		parts = append(parts, dimStyle.Render("j/k navigate  enter select  / filter  ? help  q quit"))
	case screenDetail:
		parts = append(parts, dimStyle.Render("esc back  j/k scroll  tab switch  1-4 tabs  ? help  q quit"))
	}

	return footerStyle.Render(strings.Join(parts, "  "))
}

func (m model) loadCheckpoints() tea.Cmd {
	return func() tea.Msg {
		summaries, err := m.loader.ListCheckpoints()
		if err != nil {
			return errMsg{err}
		}
		return checkpointsLoadedMsg{summaries}
	}
}

func (m model) loadDetail(id string) tea.Cmd {
	return func() tea.Msg {
		cp, err := m.loader.LoadCheckpoint(id)
		if err != nil {
			return errMsg{err}
		}
		return checkpointDetailLoadedMsg{cp}
	}
}

func (m model) loadTranscript(id string) tea.Cmd {
	return func() tea.Msg {
		entries, err := m.loader.LoadTranscript(id)
		if err != nil {
			return errMsg{err}
		}
		return transcriptLoadedMsg{entries}
	}
}

package dashboard

import (
	"fmt"
	"strings"

	"github.com/jcleira/entire-local/pkg/checkpoint"
)

func renderTabTranscript(entries []checkpoint.TranscriptEntry, width, height int, scrollOffset int) string {
	if len(entries) == 0 {
		return dimStyle.Render("  Loading transcript...")
	}

	contentWidth := width - 8
	if contentWidth < 30 {
		contentWidth = 30
	}

	var allLines []string

	allLines = append(allLines, sectionHeaderStyle.Render(fmt.Sprintf("  Transcript (%d messages)", len(entries))))
	allLines = append(allLines, "")

	for _, e := range entries {
		switch {
		case e.Role == "human" || e.Role == "user":
			content := e.Content
			if content == "" {
				continue
			}
			wrapped := wordWrap(content, contentWidth)
			block := userBubbleStyle.Width(contentWidth + 2).Render(wrapped)
			for _, line := range strings.Split(block, "\n") {
				allLines = append(allLines, "  "+line)
			}
			allLines = append(allLines, "")

		case e.Role == "assistant":
			if e.ToolName != "" {
				allLines = append(allLines, "  "+toolBadgeStyle.Render("["+e.ToolName+"]"))
				continue
			}
			content := e.Content
			if content == "" {
				continue
			}
			wrapped := wordWrap(content, contentWidth)
			block := assistantBlockStyle.Width(contentWidth + 2).Render(wrapped)
			for _, line := range strings.Split(block, "\n") {
				allLines = append(allLines, "  "+line)
			}
			allLines = append(allLines, "")

		case e.Type == "tool_result":
			allLines = append(allLines, "  "+dimStyle.Render("[result]"))

		default:
			if e.Content != "" {
				content := e.Content
				if len(content) > contentWidth {
					content = content[:contentWidth-3] + "..."
				}
				allLines = append(allLines, "  "+content)
			}
		}
	}

	maxScroll := len(allLines) - height
	if maxScroll < 0 {
		maxScroll = 0
	}
	if scrollOffset > maxScroll {
		scrollOffset = maxScroll
	}
	if scrollOffset < 0 {
		scrollOffset = 0
	}

	end := scrollOffset + height
	if end > len(allLines) {
		end = len(allLines)
	}

	visible := allLines[scrollOffset:end]

	if maxScroll > 0 {
		pos := scrollIndicatorStyle.Render(fmt.Sprintf("(%d/%d)", scrollOffset+1, maxScroll+1))
		visible = append(visible, "  "+pos)
	}

	return strings.Join(visible, "\n")
}

