package checkpoint

import (
	"bufio"
	"encoding/json"
	"strings"
	"time"
)

type flexTimestamp struct {
	Time time.Time
}

func (ft *flexTimestamp) UnmarshalJSON(data []byte) error {
	var f float64
	if err := json.Unmarshal(data, &f); err == nil {
		ft.Time = time.Unix(int64(f), 0)
		return nil
	}

	var s string
	if err := json.Unmarshal(data, &s); err == nil {
		t, err := time.Parse(time.RFC3339Nano, s)
		if err == nil {
			ft.Time = t
			return nil
		}
		t, err = time.Parse(time.RFC3339, s)
		if err == nil {
			ft.Time = t
			return nil
		}
	}

	return nil
}

type contentBlock struct {
	Type  string `json:"type"`
	Text  string `json:"text,omitempty"`
	Name  string `json:"name,omitempty"`
	ID    string `json:"id,omitempty"`
	Input json.RawMessage `json:"input,omitempty"`
}

type messageContent struct {
	Role    string         `json:"role"`
	Content []contentBlock `json:"content"`
}

type jsonlEntry struct {
	Type          string          `json:"type"`
	Role          string          `json:"role,omitempty"`
	Message       json.RawMessage `json:"message,omitempty"`
	Content       json.RawMessage `json:"content,omitempty"`
	Timestamp     flexTimestamp   `json:"timestamp"`
	ContentBlocks []contentBlock  `json:"contentBlocks,omitempty"`
}

func ParseTranscript(content string) ([]TranscriptEntry, error) {
	var entries []TranscriptEntry

	scanner := bufio.NewScanner(strings.NewReader(content))
	buf := make([]byte, 0, 1024*1024)
	scanner.Buffer(buf, 10*1024*1024)

	for scanner.Scan() {
		line := scanner.Bytes()
		if len(line) == 0 {
			continue
		}

		var entry jsonlEntry
		if err := json.Unmarshal(line, &entry); err != nil {
			continue
		}

		text, toolName := extractContent(entry)

		role := entry.Role
		if role == "" {
			role = entry.Type
		}

		entries = append(entries, TranscriptEntry{
			Type:      entry.Type,
			Role:      role,
			Content:   text,
			ToolName:  toolName,
			Timestamp: entry.Timestamp.Time,
		})
	}

	return entries, scanner.Err()
}

func extractContent(entry jsonlEntry) (string, string) {
	var toolName string

	if len(entry.ContentBlocks) > 0 {
		var text string
		for _, b := range entry.ContentBlocks {
			switch b.Type {
			case "text":
				text += b.Text
			case "tool_use":
				toolName = b.Name
			}
		}
		return text, toolName
	}

	if entry.Message != nil {
		var mc messageContent
		if json.Unmarshal(entry.Message, &mc) == nil && len(mc.Content) > 0 {
			var text string
			for _, b := range mc.Content {
				switch b.Type {
				case "text":
					text += b.Text
				case "tool_use":
					toolName = b.Name
				}
			}
			return text, toolName
		}

		var s string
		if json.Unmarshal(entry.Message, &s) == nil {
			return s, ""
		}
	}

	if entry.Content != nil {
		var blocks []contentBlock
		if json.Unmarshal(entry.Content, &blocks) == nil && len(blocks) > 0 {
			var text string
			for _, b := range blocks {
				switch b.Type {
				case "text":
					text += b.Text
				case "tool_use":
					toolName = b.Name
				}
			}
			return text, toolName
		}

		var s string
		if json.Unmarshal(entry.Content, &s) == nil {
			return s, ""
		}
	}

	return "", ""
}

package dashboard

import (
	"fmt"
	"strings"

	"github.com/charmbracelet/bubbles/key"
	tea "github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/lipgloss"

	"github.com/jcleira/entire-local/pkg/checkpoint"
)

type model struct {
	loader     *checkpoint.Loader
	summaries  []checkpoint.CheckpointSummary
	stats      checkpoint.OverviewStats
	detail     *checkpoint.Checkpoint
	transcript []checkpoint.TranscriptEntry

	screen       screen
	cursor       int
	width        int
	height       int
	filter       string
	filtering    bool
	showHelp     bool
	err          error
	detailTab    detailTab
	scrollOffset int
	maxScroll    int
}

func RunDashboard(loader *checkpoint.Loader) error {
	m := model{
		loader: loader,
		screen: screenOverview,
		width:  80,
		height: 24,
	}

	p := tea.NewProgram(m, tea.WithAltScreen())
	_, err := p.Run()
	return err
}

func (m model) Init() tea.Cmd {
	return m.loadCheckpoints()
}

func (m model) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {
	case tea.WindowSizeMsg:
		m.width = msg.Width
		m.height = msg.Height
		return m, nil

	case tea.KeyMsg:
		if m.filtering {
			return m.handleFilterInput(msg)
		}
		return m.handleKeyPress(msg)

	case checkpointsLoadedMsg:
		m.summaries = msg.summaries
		m.stats = checkpoint.ComputeStats(msg.summaries)
		return m, nil

	case checkpointDetailLoadedMsg:
		m.detail = msg.checkpoint
		return m, nil

	case transcriptLoadedMsg:
		m.transcript = msg.entries
		return m, nil

	case errMsg:
		m.err = msg.err
		return m, nil
	}

	return m, nil
}

func (m model) View() string {
	if m.showHelp {
		return renderHelp(m.width, m.height)
	}

	if m.err != nil {
		return lipgloss.Place(m.width, m.height,
			lipgloss.Center, lipgloss.Center,
			lipgloss.NewStyle().Foreground(errClr).Render("Error: "+m.err.Error()),
		)
	}

	var content string

	switch m.screen {
	case screenOverview:
		overview := renderOverview(m.stats, m.width)
		overviewLines := strings.Count(overview, "\n") + 1
		listHeight := m.height - overviewLines - 3
		if listHeight < 5 {
			listHeight = 5
		}
		list := renderCheckpointList(m.summaries, m.cursor, listHeight, m.filter, m.width)
		content = lipgloss.JoinVertical(lipgloss.Left, overview, "", list)

	case screenDetail:
		content = renderCheckpointDetail(m.detail, m.transcript, m.width, m.height-2, m.detailTab, m.scrollOffset)
	}

	footer := m.renderFooter()

	return lipgloss.JoinVertical(lipgloss.Left,
		content,
		footer,
	)
}

func (m model) handleKeyPress(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	switch {
	case key.Matches(msg, keys.Quit):
		return m, tea.Quit

	case key.Matches(msg, keys.Help):
		m.showHelp = !m.showHelp
		return m, nil

	case key.Matches(msg, keys.Refresh):
		return m, m.loadCheckpoints()

	case key.Matches(msg, keys.Filter):
		if m.screen == screenOverview {
			m.filtering = true
			return m, nil
		}
	}

	switch m.screen {
	case screenOverview:
		return m.handleOverviewKeys(msg)
	case screenDetail:
		return m.handleDetailKeys(msg)
	}

	return m, nil
}

func (m model) handleOverviewKeys(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	filtered := filterSummaries(m.summaries, m.filter)

	switch {
	case key.Matches(msg, keys.Down):
		if m.cursor < len(filtered)-1 {
			m.cursor++
		}

	case key.Matches(msg, keys.Up):
		if m.cursor > 0 {
			m.cursor--
		}

	case key.Matches(msg, keys.Enter):
		if len(filtered) > 0 && m.cursor < len(filtered) {
			selected := filtered[m.cursor]
			m.screen = screenDetail
			m.detail = nil
			m.transcript = nil
			m.detailTab = tabOverview
			m.scrollOffset = 0
			return m, tea.Batch(
				m.loadDetail(selected.ID),
				m.loadTranscript(selected.ID),
			)
		}
	}

	return m, nil
}

func (m model) handleDetailKeys(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	switch {
	case key.Matches(msg, keys.Back):
		m.screen = screenOverview
		m.detail = nil
		m.transcript = nil
		m.scrollOffset = 0
		return m, nil

	case key.Matches(msg, keys.Tab):
		m.detailTab = (m.detailTab + 1) % 4
		m.scrollOffset = 0
		return m, nil

	case key.Matches(msg, keys.ShiftTab):
		m.detailTab = (m.detailTab + 3) % 4
		m.scrollOffset = 0
		return m, nil

	case key.Matches(msg, keys.Num1):
		m.detailTab = tabOverview
		m.scrollOffset = 0
		return m, nil

	case key.Matches(msg, keys.Num2):
		m.detailTab = tabFiles
		m.scrollOffset = 0
		return m, nil

	case key.Matches(msg, keys.Num3):
		m.detailTab = tabTranscript
		m.scrollOffset = 0
		return m, nil

	case key.Matches(msg, keys.Num4):
		m.detailTab = tabPlan
		m.scrollOffset = 0
		return m, nil

	case key.Matches(msg, keys.Down):
		if m.scrollOffset < m.maxScroll {
			m.scrollOffset++
		}
		return m, nil

	case key.Matches(msg, keys.Up):
		if m.scrollOffset > 0 {
			m.scrollOffset--
		}
		return m, nil
	}

	return m, nil
}

func (m model) handleFilterInput(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	switch msg.Type {
	case tea.KeyEnter, tea.KeyEscape:
		m.filtering = false
		if msg.Type == tea.KeyEscape {
			m.filter = ""
		}
		m.cursor = 0
		return m, nil
	case tea.KeyBackspace:
		if m.filter != "" {
			m.filter = m.filter[:len(m.filter)-1]
		}
		m.cursor = 0
		return m, nil
	default:
		if len(msg.Runes) > 0 {
			m.filter += string(msg.Runes)
			m.cursor = 0
		}
		return m, nil
	}
}

func (m model) renderFooter() string {
	if m.filtering {
		return footerStyle.Render(fmt.Sprintf("Filter: %s█", m.filter))
	}

	var parts []string
	switch m.screen {
	case screenOverview:
		parts = append(parts, dimStyle.Render("j/k navigate  enter select  / filter  ? help  q quit"))
	case screenDetail:
		parts = append(parts, dimStyle.Render("esc back  j/k scroll  tab switch  1-4 tabs  ? help  q quit"))
	}

	return footerStyle.Render(strings.Join(parts, "  "))
}

func (m model) loadCheckpoints() tea.Cmd {
	return func() tea.Msg {
		summaries, err := m.loader.ListCheckpoints()
		if err != nil {
			return errMsg{err}
		}
		return checkpointsLoadedMsg{summaries}
	}
}

func (m model) loadDetail(id string) tea.Cmd {
	return func() tea.Msg {
		cp, err := m.loader.LoadCheckpoint(id)
		if err != nil {
			return errMsg{err}
		}
		return checkpointDetailLoadedMsg{cp}
	}
}

func (m model) loadTranscript(id string) tea.Cmd {
	return func() tea.Msg {
		entries, err := m.loader.LoadTranscript(id)
		if err != nil {
			return errMsg{err}
		}
		return transcriptLoadedMsg{entries}
	}
}
